import{_ as e,o as i,c as s,ag as o}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"Gateway 소유 페어링 (pairing)","description":"Gateway 소유 노드 페어링(Option B): iOS 및 기타 원격 노드용","frontmatter":{"title":"Gateway 소유 페어링 (pairing)","description":"Gateway 소유 노드 페어링(Option B): iOS 및 기타 원격 노드용"},"headers":[],"relativePath":"gateway/pairing.md","filePath":"gateway/pairing.md","lastUpdated":null}'),t={name:"gateway/pairing.md"};function n(l,a,r,d,p,c){return i(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="gateway-소유-페어링-option-b" tabindex="-1">Gateway 소유 페어링 (Option B) <a class="header-anchor" href="#gateway-소유-페어링-option-b" aria-label="Permalink to &quot;Gateway 소유 페어링 (Option B)&quot;">​</a></h1><p>Gateway 소유 페어링에서는 <strong>Gateway</strong>가 어떤 노드가 조인할 수 있는지에 대한 진실의 원천입니다. UI(macOS 앱, 향후 클라이언트)는 대기 중인 요청을 승인하거나 거부하는 프론트엔드일 뿐입니다.</p><p><strong>중요:</strong> WS 노드는 <code>connect</code> 중에 <strong>장치 페어링</strong>(role <code>node</code>)을 사용합니다. <code>node.pair.*</code>는 별도의 페어링 저장소이며 WS 핸드셰이크를 <strong>게이트하지 않습니다</strong>. 명시적으로 <code>node.pair.*</code>를 호출하는 클라이언트만 이 플로우를 사용합니다.</p><h2 id="개념" tabindex="-1">개념 <a class="header-anchor" href="#개념" aria-label="Permalink to &quot;개념&quot;">​</a></h2><ul><li><strong>Pending request</strong>: 노드가 조인을 요청했으며, 승인이 필요합니다.</li><li><strong>Paired node</strong>: 승인된 노드로, auth token이 발급되었습니다.</li><li><strong>Transport</strong>: Gateway WS 엔드포인트는 요청을 전달하지만 멤버십을 결정하지 않습니다. (레거시 TCP 브리지 지원은 제거되었습니다.)</li></ul><h2 id="페어링-작동-방식" tabindex="-1">페어링 작동 방식 <a class="header-anchor" href="#페어링-작동-방식" aria-label="Permalink to &quot;페어링 작동 방식&quot;">​</a></h2><ol><li>노드가 Gateway WS에 연결하고 페어링을 요청합니다.</li><li>Gateway가 <strong>pending request</strong>를 저장하고 <code>node.pair.requested</code>를 발행합니다.</li><li>요청을 승인하거나 거부합니다(CLI 또는 UI).</li><li>승인 시, Gateway가 <strong>새 token</strong>을 발급합니다(재페어링 시 토큰이 로테이션됩니다).</li><li>노드가 토큰을 사용하여 재연결하고 이제 &quot;paired&quot; 상태가 됩니다.</li></ol><p>Pending request는 <strong>5분</strong> 후 자동으로 만료됩니다.</p><h2 id="cli-워크플로-헤드리스-친화적" tabindex="-1">CLI 워크플로 (헤드리스 친화적) <a class="header-anchor" href="#cli-워크플로-헤드리스-친화적" aria-label="Permalink to &quot;CLI 워크플로 (헤드리스 친화적)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pending</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reject</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rename</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Living Room iPad&quot;</span></span></code></pre></div><p><code>nodes status</code>는 paired/connected 노드와 그 capability를 보여줍니다.</p><h2 id="api-표면-게이트웨이-프로토콜" tabindex="-1">API 표면 (게이트웨이 프로토콜) <a class="header-anchor" href="#api-표면-게이트웨이-프로토콜" aria-label="Permalink to &quot;API 표면 (게이트웨이 프로토콜)&quot;">​</a></h2><p>Events:</p><ul><li><code>node.pair.requested</code> — 새 pending request가 생성될 때 발행됩니다.</li><li><code>node.pair.resolved</code> — 요청이 승인/거부/만료될 때 발행됩니다.</li></ul><p>Methods:</p><ul><li><code>node.pair.request</code> — pending request 생성 또는 재사용.</li><li><code>node.pair.list</code> — pending + paired 노드 목록(<code>operator.pairing</code>).</li><li><code>node.pair.approve</code> — pending request 승인(토큰 발급).</li><li><code>node.pair.reject</code> — pending request 거부.</li><li><code>node.pair.verify</code> — <code>{ nodeId, token }</code> 검증.</li></ul><p>참고 사항:</p><ul><li><code>node.pair.request</code>는 노드별로 멱등적입니다: 반복 호출은 동일한 pending request를 반환합니다.</li><li>동일한 pending 노드에 대한 반복 요청은 저장된 노드 메타데이터와 운영자 가시성을 위한 최신 허용 목록 선언 명령 스냅샷도 갱신합니다.</li><li>승인은 <strong>항상</strong> 새 토큰을 생성합니다. <code>node.pair.request</code>에서는 토큰이 반환되지 않습니다.</li><li>요청에는 자동 승인 플로우용 힌트로 <code>silent: true</code>가 포함될 수 있습니다.</li><li><code>node.pair.approve</code>는 pending request의 선언된 명령을 사용하여 추가 승인 스코프를 강제합니다: <ul><li>명령 없는 요청: <code>operator.pairing</code></li><li>비 exec 명령 요청: <code>operator.pairing</code> + <code>operator.write</code></li><li><code>system.run</code> / <code>system.run.prepare</code> / <code>system.which</code> 요청: <code>operator.pairing</code> + <code>operator.admin</code></li></ul></li></ul><p>중요:</p><ul><li>노드 페어링은 신뢰/아이덴티티 플로우와 토큰 발급입니다.</li><li>이는 노드별 라이브 노드 명령 표면을 <strong>고정하지 않습니다</strong>.</li><li>라이브 노드 명령은 게이트웨이의 전역 노드 명령 정책(<code>gateway.nodes.allowCommands</code> / <code>denyCommands</code>)이 적용된 후 노드가 connect 시 선언하는 것에서 옵니다.</li><li>노드별 <code>system.run</code> allow/ask 정책은 페어링 레코드가 아닌 노드의 <code>exec.approvals.node.*</code>에 있습니다.</li></ul><h2 id="노드-명령-게이팅-2026-3-31" tabindex="-1">노드 명령 게이팅 (2026.3.31+) <a class="header-anchor" href="#노드-명령-게이팅-2026-3-31" aria-label="Permalink to &quot;노드 명령 게이팅 (2026.3.31+)&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>Breaking change:</strong> <code>2026.3.31</code>부터 노드 페어링이 승인될 때까지 노드 명령이 비활성화됩니다. 장치 페어링만으로는 더 이상 선언된 노드 명령을 노출하기에 충분하지 않습니다.</p></div><p>노드가 처음 연결될 때, 페어링이 자동으로 요청됩니다. 페어링 요청이 승인될 때까지, 해당 노드의 모든 pending 노드 명령은 필터링되며 실행되지 않습니다. 페어링 승인을 통해 신뢰가 확립되면, 노드의 선언된 명령은 정상적인 명령 정책의 대상이 되어 사용 가능해집니다.</p><p>이는 다음을 의미합니다:</p><ul><li>이전에 장치 페어링만으로 명령을 노출하는 데 의존했던 노드는 이제 노드 페어링을 완료해야 합니다.</li><li>페어링 승인 이전에 큐에 들어간 명령은 지연(deferred)되지 않고 삭제(dropped)됩니다.</li></ul><h2 id="노드-이벤트-신뢰-경계-2026-3-31" tabindex="-1">노드 이벤트 신뢰 경계 (2026.3.31+) <a class="header-anchor" href="#노드-이벤트-신뢰-경계-2026-3-31" aria-label="Permalink to &quot;노드 이벤트 신뢰 경계 (2026.3.31+)&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>Breaking change:</strong> 노드에서 시작된 실행은 이제 축소된 신뢰 표면에 머뭅니다.</p></div><p>노드에서 시작된 요약 및 관련 세션 이벤트는 의도된 신뢰 표면으로 제한됩니다. 이전에 더 넓은 호스트 또는 세션 툴 접근에 의존했던 알림 기반 또는 노드 트리거 플로우는 조정이 필요할 수 있습니다. 이 강화는 노드 이벤트가 노드의 신뢰 경계가 허용하는 것을 넘어 호스트 레벨 툴 접근으로 상승하는 것을 방지합니다.</p><h2 id="자동-승인-macos-앱" tabindex="-1">자동 승인 (macOS 앱) <a class="header-anchor" href="#자동-승인-macos-앱" aria-label="Permalink to &quot;자동 승인 (macOS 앱)&quot;">​</a></h2><p>macOS 앱은 다음의 경우 선택적으로 <strong>silent 승인</strong>을 시도할 수 있습니다:</p><ul><li>요청이 <code>silent</code>로 표시되어 있고</li><li>앱이 동일한 사용자로 게이트웨이 호스트에 대한 SSH 연결을 검증할 수 있는 경우.</li></ul><p>silent 승인이 실패하면, 일반적인 &quot;Approve/Reject&quot; 프롬프트로 폴백됩니다.</p><h2 id="메타데이터-업그레이드-자동-승인" tabindex="-1">메타데이터 업그레이드 자동 승인 <a class="header-anchor" href="#메타데이터-업그레이드-자동-승인" aria-label="Permalink to &quot;메타데이터 업그레이드 자동 승인&quot;">​</a></h2><p>이미 페어링된 장치가 민감하지 않은 메타데이터 변경(예: 표시 이름 또는 클라이언트 플랫폼 힌트)만으로 재연결하는 경우, OpenClaw는 이를 <code>metadata-upgrade</code>로 취급합니다. Silent 자동 승인은 좁게 제한됩니다: loopback을 통해 공유 토큰 또는 password의 소유를 이미 증명한 신뢰할 수 있는 로컬 CLI/helper 재연결에만 적용됩니다. 브라우저/Control UI 클라이언트와 원격 클라이언트는 여전히 명시적 재승인 플로우를 사용합니다. 스코프 업그레이드(read에서 write/admin으로) 및 공개 키 변경은 메타데이터 업그레이드 자동 승인의 <strong>대상이 아닙니다</strong> — 이는 명시적 재승인 요청으로 유지됩니다.</p><h2 id="qr-페어링-헬퍼" tabindex="-1">QR 페어링 헬퍼 <a class="header-anchor" href="#qr-페어링-헬퍼" aria-label="Permalink to &quot;QR 페어링 헬퍼&quot;">​</a></h2><p><code>/pair qr</code>은 페어링 페이로드를 구조화된 미디어로 렌더링하여 모바일 및 브라우저 클라이언트가 직접 스캔할 수 있도록 합니다.</p><p>장치를 삭제하면 해당 장치 id에 대한 모든 오래된 pending 페어링 요청도 정리되므로, 취소 후에는 <code>nodes pending</code>에 고아 행이 표시되지 않습니다.</p><h2 id="로컬리티-locality-및-forwarded-헤더" tabindex="-1">로컬리티(locality) 및 forwarded 헤더 <a class="header-anchor" href="#로컬리티-locality-및-forwarded-헤더" aria-label="Permalink to &quot;로컬리티(locality) 및 forwarded 헤더&quot;">​</a></h2><p>Gateway pairing은 raw 소켓과 상위 프록시 증거가 모두 일치할 때만 연결을 loopback으로 취급합니다. 요청이 loopback에 도착했지만 비로컬 원본을 가리키는 <code>X-Forwarded-For</code> / <code>X-Forwarded-Host</code> / <code>X-Forwarded-Proto</code> 헤더를 포함하는 경우, 해당 forwarded-header 증거가 loopback 로컬리티 주장을 실격시킵니다. 그러면 페어링 경로는 요청을 동일 호스트 연결로 조용히 취급하는 대신 명시적 승인을 요구합니다. 운영자 인증에 대한 동등한 규칙은 <a href="/openclaw-docs-ko/gateway/trusted-proxy-auth">신뢰할 수 있는 프록시 인증</a>을 참조하십시오.</p><h2 id="저장소-로컬-비공개" tabindex="-1">저장소 (로컬, 비공개) <a class="header-anchor" href="#저장소-로컬-비공개" aria-label="Permalink to &quot;저장소 (로컬, 비공개)&quot;">​</a></h2><p>페어링 상태는 Gateway state 디렉토리(기본값 <code>~/.openclaw</code>) 아래에 저장됩니다:</p><ul><li><code>~/.openclaw/nodes/paired.json</code></li><li><code>~/.openclaw/nodes/pending.json</code></li></ul><p><code>OPENCLAW_STATE_DIR</code>을 재정의하면, <code>nodes/</code> 폴더가 그와 함께 이동합니다.</p><p>보안 참고:</p><ul><li>토큰은 시크릿입니다. <code>paired.json</code>을 민감 정보로 취급하십시오.</li><li>토큰을 로테이션하려면 재승인(또는 노드 항목 삭제)이 필요합니다.</li></ul><h2 id="transport-동작" tabindex="-1">Transport 동작 <a class="header-anchor" href="#transport-동작" aria-label="Permalink to &quot;Transport 동작&quot;">​</a></h2><ul><li>Transport는 <strong>stateless</strong>입니다. 멤버십을 저장하지 않습니다.</li><li>Gateway가 오프라인이거나 페어링이 비활성화된 경우, 노드는 페어링할 수 없습니다.</li><li>Gateway가 원격 모드인 경우, 페어링은 여전히 원격 Gateway의 저장소에 대해 수행됩니다.</li></ul><h2 id="관련" tabindex="-1">관련 <a class="header-anchor" href="#관련" aria-label="Permalink to &quot;관련&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/channels/pairing">채널 페어링</a></li><li><a href="/openclaw-docs-ko/nodes/">노드</a></li><li><a href="/openclaw-docs-ko/cli/devices">Devices CLI</a></li></ul>`,49)])])}const g=e(t,[["render",n]]);export{k as __pageData,g as default};
